/**
 * @name ZipEntry name to File without canonical path check
 * @description ZipEntry names are used to construct file paths without checking canonical path containment
 * @kind problem
 * @problem.severity error
 * @id java/zip-slip-no-canonical-check
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

// Find new File(dir, entryName) where ZipEntry.getName() flows into entryName
// but there is no getCanonicalPath() or canonicalize call nearby

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }

  // Allow flow if canonical path check is done
  predicate isBarrier(DataFlow::Node node) {
    // If the value is passed to getCanonicalPath or similar
    exists(MethodCall mc |
      mc.getMethod().hasName("getCanonicalPath") and
      DataFlow::localFlow(node, DataFlow::exprNode(mc.getQualifier()))
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), "ZipEntry name '" + source.getNode() + "' flows to File constructor without canonical path check at line " + sink.getNode().getLocation().getStartLine() + " in " + sink.getNode().getLocation().getFile().getRelativePath()

/**
 * @name ZipEntry name flows to FileOutputStream - actual Zip Slip write
 * @description ZipEntry name is used to create a FileOutputStream, allowing file writes outside target directory
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip-write
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ZipSlipWriteConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileWriter
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileWriter") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Files.newOutputStream or Files.copy target
    exists(MethodCall mc |
      mc.getMethod().hasName("newOutputStream") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Files") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("copy") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Files") and
      sink.asExpr() = mc.getArgument(1)
    )
    or
    // BufferedOutputStream/FileOutputStream via File
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ZipSlipWriteFlow = TaintTracking::Global<ZipSlipWriteConfig>;
import ZipSlipWriteFlow::PathGraph

from ZipSlipWriteFlow::PathNode source, ZipSlipWriteFlow::PathNode sink
where ZipSlipWriteFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ZipEntry name flows to file write operation - Zip Slip vulnerability from $@.", source.getNode(), "ZipEntry.getName()"

/**
 * @name ZipEntry name flows to directory creation without canonical path check
 * @description ZipEntry names flow to mkdirs/mkdir without verifying the path stays within target dir
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-entry-directory-creation
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ZipDirConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // mkdir/mkdirs on a File
    exists(MethodCall mc |
      (mc.getMethod().hasName("mkdirs") or mc.getMethod().hasName("mkdir")) and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.io", "File") and
      DataFlow::localFlow(sink, DataFlow::exprNode(mc.getQualifier()))
    )
    or
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ZipDirFlow = TaintTracking::Global<ZipDirConfig>;
import ZipDirFlow::PathGraph

from ZipDirFlow::PathNode source, ZipDirFlow::PathNode sink
where ZipDirFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ZipEntry name flows to directory/file creation - potential path traversal from $@.", source.getNode(), "ZipEntry.getName()"
